export interface ConversationCallInput {
  id: string;
  sessionId?: string;
  cost: number;
  tokens: { input: number; output: number; total: number };
  model: string;
  createdAt: string;
}

export interface ConversationGroup {
  sessionId: string;
  calls: ConversationCallInput[];
  totalCost: number;
  totalTokens: number;
  callCount: number;
  models: string[];
  startedAt: string;
  endedAt: string;
}

export interface GroupConversationsOutput {
  conversations: ConversationGroup[];
  ungroupedCount: number;
}

/**
 * Group LLM calls by conversation/session ID and sum costs.
 * Calls without a sessionId are counted as ungrouped.
 */
export function groupConversationCosts(
  calls: ConversationCallInput[]
): GroupConversationsOutput {
  const map = new Map<string, ConversationCallInput[]>();
  let ungroupedCount = 0;

  for (const call of calls) {
    if (!call.sessionId) {
      ungroupedCount++;
      continue;
    }
    const group = map.get(call.sessionId) ?? [];
    group.push(call);
    map.set(call.sessionId, group);
  }

  const conversations: ConversationGroup[] = [];

  for (const [sessionId, groupCalls] of map.entries()) {
    const sorted = [...groupCalls].sort(
      (a, b) =>
        new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
    );
    const models = [...new Set(sorted.map((c) => c.model))];

    conversations.push({
      sessionId,
      calls: sorted,
      totalCost: sorted.reduce((s, c) => s + c.cost, 0),
      totalTokens: sorted.reduce((s, c) => s + c.tokens.total, 0),
      callCount: sorted.length,
      models,
      startedAt: sorted[0]!.createdAt,
      endedAt: sorted[sorted.length - 1]!.createdAt,
    });
  }

  conversations.sort((a, b) => b.totalCost - a.totalCost);
  return { conversations, ungroupedCount };
}
